import{c as r,Q as a,j as e,m as o}from"./chunks/framework.DpF7k2f3.js";const g=JSON.parse('{"title":"第8章 プロンプトエンジニアリングからエージェント開発へ","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part3-practice/chapter8.md","filePath":"ja/part3-practice/chapter8.md"}'),n={name:"ja/part3-practice/chapter8.md"};function p(s,t,i,l,c,h){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="第8章-プロンプトエンジニアリングからエージェント開発へ" tabindex="-1">第8章 プロンプトエンジニアリングからエージェント開発へ <a class="header-anchor" href="#第8章-プロンプトエンジニアリングからエージェント開発へ" aria-label="Permalink to &quot;第8章 プロンプトエンジニアリングからエージェント開発へ&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>正式开始之前、先に一つ質問させてください：假设你是2023年3月入行的AI开发者，那时候最火的是什么？是Prompt工程师——听起来很酷但实际上就是「会写提示词」的岗位。当時のAIアプリ開発は简单得令人发指：你写一个Prompt，AI返回答案，齐活。</p><p>但是如果现在（2026年）还想靠「写Prompt」这招走天下，那大概率会饿死在沙滩上。</p><p>この章の核心任务是帮你<strong>建立全局视野</strong>。你会清楚地看到：</p><ol><li><strong>为什么Prompt工程只是起点</strong>：它能做什么，它的天花板在哪里</li><li><strong>Chain是怎么解决这些天花板的</strong>：最早的工程化实践是什么样的</li><li><strong>Agent为什么是必然演进</strong>：从「我让你做什么」到「你自己决定做什么」</li><li><strong>Agent助理意味着什么</strong>：加上记忆、人格、长期目标后的质变</li><li><strong>你现在应该站在哪里</strong>：2026年のエコシステムマップと選定基準</li></ol><p><strong>前置知识</strong>：第5章プロンプトエンジニアリング基礎、第7章AIエージェントコアロジック。</p><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter8.html">中文版阅读</a></p></blockquote>',9)])])}const d=r(n,[["render",p]]);export{g as __pageData,d as default};
